def move_zeroes(nums):
    left = 0
    for right in range(len(nums)):
        if nums[right] != 0:
            nums[left], nums[right] = nums[right], nums[left]
            left += 1
    return nums

code.javascript:
function moveZeroes(nums) {
  let left = 0;
  for (let right = 0; right < nums.length; right++) {
    if (nums[right] !== 0) {
      const tmp = nums[left];
      nums[left] = nums[right];
      nums[right] = tmp;
      left++;
    }
  }
  return nums;
}

code.typescript:
function moveZeroes(nums: number[]): number[] {
  let left = 0;
  for (let right = 0; right < nums.length; right++) {
    if (nums[right] !== 0) {
      const tmp = nums[left];
      nums[left] = nums[right];
      nums[right] = tmp;
      left++;
    }
  }
  return nums;
}
